# Claude Zombies - multi-floor demo map
#
# Demonstrates vertical / overlapping floors (docs/multi-floor-maps.md).
# A map is a list of SECTORs (flat floor areas at a height) joined by RAMPs
# (slopes that are also the AI nav edges via LINK). Every placed entity lives
# inside a sector and takes its floor height from it, so a perk on the deck
# stands at the deck's height automatically.
#   SECTOR <name> x z sx sz y
#   RAMP   <name> x z sx sz yLow yHigh X|Z [LINK a b]

NAME Multi-Floor Demo

ATMOSPHERE
    fog       18 22 35  14 70
    sky_tint  255 255 255
END

# Ground level (spawns + ground gameplay)
SECTOR ground  0 0  80 80  0
    SPAWN PLAYER  0 0
    SPAWN PLAYER  2 0
    SPAWN PLAYER -2 0
    SPAWN PLAYER  0 2

    OBSTACLE -12 -8    6 3
    OBSTACLE -20  12   5 5 3
    OBSTACLE -10  20   4 4 3

    WALLBUY -39.45 18     +x  SMG
    WALLBUY -15   -39.45  +z  RIFLE

    WINDOW -40   -8   +x
    WINDOW -18   40   -z

    PERK  -8  12 JUG
    PERK   4  -8 SPEED

    MBOX -22 15
    PAP  -25 -20
END

# Elevated deck over the eastern half (Y=4) — overlaps the ground in XZ.
# The mystery-box and a perk up here sit at deck height automatically.
SECTOR deck  15 -10  18 18  4
    PERK 15 -10 DTAP
    MBOX 20 -6
END

# Ramp from the ground (Y0) up to the deck (Y4), sloping along +X, and the
# nav edge that lets zombies chase the player up onto the deck.
RAMP ramp_deck  2 -10  8 6  0 4 X  LINK ground deck
END

# A higher catwalk (Y=8) reached from the deck by a second ramp.
SECTOR catwalk  15 20  12 6  8
    WALLBUY 21 20  -x  RAYGUN
    PERK    15 20  STAMIN
END

RAMP ramp_catwalk  15 6  8 8  4 8 Z  LINK deck catwalk
END
